  "title": "Preparation of Hematite Core",
  "purpose": "To synthesize the 1.0 micron ellipsoidal hematite core.",
  "instructions": [
    "Dissolve iron(III) chloride in deionized water.",
    "Add sodium hydroxide solution to precipitate iron hydroxide.",
    "Heat the mixture to 90°C for 2 hours to form hematite particles.",
    "Wash and dry the particles."
  ],
  "parameters": {
    "reagent_amounts": [
      "Iron(III) chloride: 10 g",
      "Sodium hydroxide: 5 g"
    ],
